-- ============================================
-- Legislacao full-site: orleans-brandao / Camara Dados Abertos / projetos_lei
-- Seed ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/141402
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes?idDeputadoAutor=141402&ordem=DESC&ordenarPor=id&itens=100&pagina=1..3
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = orleans-brandao-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: todas as 3 paginas oficiais Camara para idDeputadoAutor=141402
-- foram verificadas por detalhe e autoria; somente 137 rows entram
-- porque /autores confirmou tipo Deputado(a), ordemAssinatura=1 e nome/uri compativel.
--
-- O recorte e ampliado parcial de autoria parlamentar Camara. Nao e completo_provado.
--
-- Esta migration escreve apenas em projetos_lei.
-- Esta migration NAO escreve em historico_politico.
-- Esta migration NAO deleta nem trunca rows.
-- Esta migration insere rows ausentes e atualiza coverage/metadata somente em rows alvo Camara sem coverage_id divergente.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  projetos_total int;
  target_present int;
  target_count int;
  target_with_other_coverage int;
  mandato_camara_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'orleans-brandao';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'orleans-brandao: candidato ausente neste banco local/CI minimo; seed projetos_lei Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO projetos_total
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'orleans-brandao-camara-autoria-principal-ampliado-parcial-lote-a-20260506';

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('620532', '619212', '609375', '607682', '607493', '607325', '607324', '602866', '602864', '602359', '601644', '599979', '599956', '594163', '592092', '590061', '590060', '572119', '568129', '567007', '565009', '562678', '561987', '558505', '553874', '550625', '550623', '550622', '549418', '542545', '536570', '535531', '535530', '511797', '511794', '508797', '507739', '502509', '499662', '499511', '498572', '496849', '496848', '496689', '495505', '495497', '494570', '493728', '492222', '491238', '491237', '490195', '490194', '489533', '489313', '489262', '489189', '487752', '486704', '486703', '485638', '476215', '472216', '471589', '471254', '469731', '469295', '468728', '466258', '464472', '464336', '464335', '462655', '462372', '461687', '461686', '459400', '458466', '458136', '457716', '457715', '457173', '456658', '453491', '453471', '452742', '452317', '449885', '447856', '440661', '437417', '429473', '427957', '421492', '406093', '401123', '397580', '391872', '391033', '390452', '389905', '388074', '386706', '382136', '379701', '378489', '376544', '376541', '376538', '370778', '369908', '368374', '368373', '368372', '366377', '365204', '363717', '363194', '363193', '363192', '363191', '363190', '363189', '363188', '360912', '359991', '356605', '356604', '355732', '354778', '353866', '350956', '350600', '345776', '345774', '344467', '342745');

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('620532', '619212', '609375', '607682', '607493', '607325', '607324', '602866', '602864', '602359', '601644', '599979', '599956', '594163', '592092', '590061', '590060', '572119', '568129', '567007', '565009', '562678', '561987', '558505', '553874', '550625', '550623', '550622', '549418', '542545', '536570', '535531', '535530', '511797', '511794', '508797', '507739', '502509', '499662', '499511', '498572', '496849', '496848', '496689', '495505', '495497', '494570', '493728', '492222', '491238', '491237', '490195', '490194', '489533', '489313', '489262', '489189', '487752', '486704', '486703', '485638', '476215', '472216', '471589', '471254', '469731', '469295', '468728', '466258', '464472', '464336', '464335', '462655', '462372', '461687', '461686', '459400', '458466', '458136', '457716', '457715', '457173', '456658', '453491', '453471', '452742', '452317', '449885', '447856', '440661', '437417', '429473', '427957', '421492', '406093', '401123', '397580', '391872', '391033', '390452', '389905', '388074', '386706', '382136', '379701', '378489', '376544', '376541', '376538', '370778', '369908', '368374', '368373', '368372', '366377', '365204', '363717', '363194', '363193', '363192', '363191', '363190', '363189', '363188', '360912', '359991', '356605', '356604', '355732', '354778', '353866', '350956', '350600', '345776', '345774', '344467', '342745')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'orleans-brandao-camara-autoria-principal-ampliado-parcial-lote-a-20260506';

  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao orleans-brandao: % rows alvo Camara ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  IF projetos_total NOT IN (0, 137) THEN
    RAISE EXCEPTION 'Pre-condicao orleans-brandao: esperadas 0 rows atuais ou 137 rows alvo idempotentes em projetos_lei, encontradas %', projetos_total;
  END IF;

  IF projetos_total = 137 AND target_count <> 137 THEN
    RAISE EXCEPTION 'Pre-condicao orleans-brandao: 137 rows existentes, mas apenas % com coverage_id alvo', target_count;
  END IF;

  SELECT count(*) INTO mandato_camara_count
  FROM historico_politico hp
  WHERE hp.candidato_id = cand_id
    AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
    AND (hp.cargo ILIKE '%Deputado Federal%' OR hp.cargo_canonico = 'Deputado Federal')
    AND UPPER(COALESCE(hp.estado, '')) = 'MA'
    AND COALESCE(hp.periodo_inicio, 9999) <= 2014
    AND COALESCE(hp.periodo_fim, 9999) >= 2007;

  IF mandato_camara_count < 1 THEN
    RAISE EXCEPTION 'Pre-condicao orleans-brandao: mandato Deputado Federal/MA 2007-2014 nao encontrado em historico_politico';
  END IF;

END $$;

