    ('PFC', '11', 2011, 'Com fulcro no art. 100, § 1º, combinado com os art. 60, inciso II, e art. 61 do Regimento Interno da Câmara dos Deputados, proponho a Vossa Excelência que, ouvido o Plenário desta Comissão, se digne adotar as medidas necessárias para que, com auxílio do Tribunal de Contas da União, realize ato de fiscalização objetivando avaliar a regularização da gestão e execução do Programa Nacional de Inclusão de Jovens (Projovem).', 'Camara', '499662', 'https://www.camara.leg.br/proposicoesWeb/prop_mostrarintegra?codteor=863268', 'orleans-brandao-camara-autoria-principal-ampliado-parcial-lote-a-20260506', 'inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506', '{"proposicao_id_api":"499662","data_apresentacao":"2011-04-27T16:19","fonte":"Camara Dados Abertos","camara_id_deputado":141402,"autor_nome":"Carlos Brandão","autor_tipo":"Deputado(a)","autor_uri":"https://dadosabertos.camara.leg.br/api/v2/deputados/141402","ordem_assinatura":1,"total_autores":1,"detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/499662","autores_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/499662/autores","public_url":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/499662","coverage_id":"orleans-brandao-camara-autoria-principal-ampliado-parcial-lote-a-20260506","coverage_scope":"inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506","lote":"A","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"orleans-brandao-camara-lote-a-20260506","autoria_principal_verificada":true,"snapshot_consulta_em":"2026-05-06T15:14:20.266Z"}'::jsonb),
