WITH target AS (
  SELECT c.id AS candidato_id
  FROM candidatos c
  WHERE c.slug = 'orleans-brandao'
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  target.candidato_id,
  seed.tipo,
  seed.numero,
  seed.ano,
  seed.ementa,
  seed.fonte,
  seed.proposicao_id_api,
  seed.url_inteiro_teor,
  seed.coverage_id,
  seed.coverage_scope,
  seed.metadata
FROM target
CROSS JOIN _seed_orleans_brandao_camara_lote_a_projetos AS seed
ON CONFLICT (candidato_id, proposicao_id_api) DO UPDATE SET
  tipo = EXCLUDED.tipo,
  numero = EXCLUDED.numero,
  ano = EXCLUDED.ano,
  ementa = EXCLUDED.ementa,
  fonte = EXCLUDED.fonte,
  url_inteiro_teor = EXCLUDED.url_inteiro_teor,
  coverage_id = EXCLUDED.coverage_id,
  coverage_scope = EXCLUDED.coverage_scope,
  metadata = COALESCE(projetos_lei.metadata, '{}'::jsonb) || EXCLUDED.metadata
WHERE projetos_lei.coverage_id IS NULL
   OR projetos_lei.coverage_id = EXCLUDED.coverage_id;

DO $$
DECLARE
  cand_id uuid;
  total_count int;
  target_count int;
  scope_count int;
  other_slugs_with_target int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'orleans-brandao';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'orleans-brandao: pos-condicao pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO total_count
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('620532', '619212', '609375', '607682', '607493', '607325', '607324', '602866', '602864', '602359', '601644', '599979', '599956', '594163', '592092', '590061', '590060', '572119', '568129', '567007', '565009', '562678', '561987', '558505', '553874', '550625', '550623', '550622', '549418', '542545', '536570', '535531', '535530', '511797', '511794', '508797', '507739', '502509', '499662', '499511', '498572', '496849', '496848', '496689', '495505', '495497', '494570', '493728', '492222', '491238', '491237', '490195', '490194', '489533', '489313', '489262', '489189', '487752', '486704', '486703', '485638', '476215', '472216', '471589', '471254', '469731', '469295', '468728', '466258', '464472', '464336', '464335', '462655', '462372', '461687', '461686', '459400', '458466', '458136', '457716', '457715', '457173', '456658', '453491', '453471', '452742', '452317', '449885', '447856', '440661', '437417', '429473', '427957', '421492', '406093', '401123', '397580', '391872', '391033', '390452', '389905', '388074', '386706', '382136', '379701', '378489', '376544', '376541', '376538', '370778', '369908', '368374', '368373', '368372', '366377', '365204', '363717', '363194', '363193', '363192', '363191', '363190', '363189', '363188', '360912', '359991', '356605', '356604', '355732', '354778', '353866', '350956', '350600', '345776', '345774', '344467', '342745');

  SELECT count(*) INTO scope_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'orleans-brandao-camara-autoria-principal-ampliado-parcial-lote-a-20260506'
    AND coverage_scope = 'inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506';

  SELECT count(*) INTO other_slugs_with_target
  FROM projetos_lei
  WHERE candidato_id <> cand_id
    AND coverage_id = 'orleans-brandao-camara-autoria-principal-ampliado-parcial-lote-a-20260506';

  IF target_count <> 137 THEN
    RAISE EXCEPTION 'Pos-apply orleans-brandao: esperadas 137 rows alvo Camara em projetos_lei, encontradas %', target_count;
  END IF;

  IF scope_count <> 137 THEN
    RAISE EXCEPTION 'Pos-apply orleans-brandao: esperadas 137 rows com coverage_id/scope alvo, encontradas %', scope_count;
  END IF;

  IF total_count <> 137 THEN
    RAISE EXCEPTION 'Pos-apply orleans-brandao: total projetos_lei esperado 137, encontrado %', total_count;
  END IF;

  IF other_slugs_with_target <> 0 THEN
    RAISE EXCEPTION 'Pos-apply orleans-brandao: % rows de outros slugs com coverage_id alvo', other_slugs_with_target;
  END IF;

  RAISE NOTICE 'Pos-apply orleans-brandao Camara Lote A: projetos_lei=% coverage_scope=%', total_count, scope_count;
END $$;
